samples.createWebhookSubscription:
const subscription = await wf.unwrap(
  wf.raw.createWebhookSubscription({
    path: { campaign_id: 1234 },
    body: {
      target_url: "https://example.com/wefunder/webhooks",
      events: ["investment.confirmed", "investment.canceled"],
    },
  }),
);
console.log(subscription);

samples.guides/client-credentials:
const wf = await Wefunder.fromClientCredentials({
  clientId: process.env.WEFUNDER_CLIENT_ID!,
  clientSecret: process.env.WEFUNDER_CLIENT_SECRET!,
  scopes: ["read:public"],
});

console.log("mode:", wf.mode); // "live" or "test", from the token prefix

// client_credentials holds only read:public — browse public offerings.
// (wf.users.me() would throw 403 insufficient_scope: it needs read:profile.)
for await (const offering of wf.offerings.all()) {
  console.log(offering.id);
}

samples.listInvestments:
// Auto-paginate the full history lazily:
for await (const investment of wf.investments.all()) {
  console.log(investment.id);
}

// Or grab one page with its meta (next_cursor, etc.):
const page = await wf.investments.list();
console.log(page.data?.length, page.meta?.next_cursor);

samples.listOfferings:
// Browse live offerings, sorted. The cursor is opaque and handled for you.
const page = await wf.offerings.list({ sort: "most_raised" });
for (const offering of page.data ?? []) {
  console.log(offering.id, offering.attributes?.company_name);
}

// Or stream every offering lazily, one page fetched at a time:
for await (const offering of wf.offerings.all({ sort: "newest" })) {
  console.log(offering.id);
}
